import { createClient } from "@/app/lib/supabase/server";
import { formatDate } from "@/app/lib/show-workflow";

export default async function AdminMarkusPage() {
  const supabase = await createClient();
  const today = new Date().toISOString().slice(0, 10);

  const { data: shows, error } = await supabase
    .from("shows")
    .select("*")
    .order("show_date", { ascending: true });

  if (error) {
    return (
      <div className="px-6 py-8">
        <div className="mx-auto max-w-[1120px] rounded-[2rem] bg-white p-8 text-red-600 shadow-sm ring-1 ring-black/5">
          Markus-Ansicht konnte nicht geladen werden.
        </div>
      </div>
    );
  }

  const visibleShows = (shows ?? []).filter((show) => {
    const markusIncluded =
      show.markus_included === true ||
      show.markus_included === "true" ||
      show.markus_included === 1;

    const isUpcoming = !show.show_date || show.show_date >= today;

    return (
      markusIncluded &&
      isUpcoming &&
      show.internal_status !== "archiv" &&
      show.internal_status !== "archiviert" &&
      show.internal_status !== "abgeschlossen"
    );
  });

  return (
    <div className="px-6 py-8">
      <div className="mx-auto max-w-[1120px] space-y-6">
        <header className="relative overflow-hidden rounded-[2.2rem] bg-[#111] p-8 text-white shadow-xl shadow-black/10">
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_82%_18%,rgba(255,105,180,0.38),transparent_27%),radial-gradient(circle_at_35%_20%,rgba(255,145,60,0.28),transparent_34%),radial-gradient(circle_at_65%_90%,rgba(190,255,90,0.16),transparent_28%)]" />

          <div className="absolute right-8 top-7 rounded-[2rem] bg-white/10 px-6 py-5 text-center ring-1 ring-white/10 backdrop-blur">
            <p className="text-xs font-black uppercase tracking-wide text-white/45">
              Shows
            </p>
            <p className="mt-1 text-4xl font-black">{visibleShows.length}</p>
          </div>

          <div className="absolute bottom-7 right-44 text-5xl opacity-70">
            🎹
          </div>
          <div className="absolute right-20 top-28 text-3xl opacity-50">
            🎵
          </div>
          <div className="absolute bottom-10 right-20 text-3xl opacity-40">
            ✨
          </div>

          <div className="relative max-w-2xl">
            <p className="text-xs font-black uppercase tracking-[0.28em] text-white/45">
              Primakavi · Markus
            </p>

            <h1 className="mt-4 text-4xl font-black tracking-tight md:text-5xl">
              Markus-Ansicht
            </h1>

            <p className="mt-4 max-w-xl text-sm leading-relaxed text-white/65">
              Interne Vorschau der reduzierten Piano-Ansicht: nur Termine,
              Zeiten, Technik, Ablauf und Kontakt.
            </p>

            <div className="mt-7 flex flex-wrap gap-2">
              <span className="rounded-full bg-white/10 px-4 py-2 text-xs font-black text-white ring-1 ring-white/10">
                🎹 Piano-Fokus
              </span>
              <span className="rounded-full bg-white/10 px-4 py-2 text-xs font-black text-white ring-1 ring-white/10">
                Read only
              </span>
              <span className="rounded-full bg-white/10 px-4 py-2 text-xs font-black text-white ring-1 ring-white/10">
                Kommende Shows
              </span>
            </div>
          </div>
        </header>

        {visibleShows.length === 0 ? (
          <div className="rounded-[2rem] bg-white p-10 text-center text-zinc-500 shadow-sm ring-1 ring-black/5">
            Aktuell keine kommenden Shows für Markus gefunden.
          </div>
        ) : (
          <div className="space-y-5">
            {visibleShows.map((show) => (
              <MarkusCard key={show.id} show={show} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

function MarkusCard({ show }: { show: any }) {
  return (
    <article className="rounded-[2rem] bg-white p-5 shadow-xl shadow-zinc-200/60 ring-1 ring-black/5">
      <div className="rounded-[1.5rem] bg-[#fbf7ef] p-5">
        <div className="grid gap-5 lg:grid-cols-[140px_1fr_250px] lg:items-start">
          <div>
            <p className="text-xl font-black">{formatDate(show.show_date)}</p>
            <p className="mt-1 text-sm font-bold text-zinc-500">
              {show.weekday || "—"}
            </p>
          </div>

          <div>
            <div className="flex flex-wrap items-center gap-2">
              <h2 className="text-2xl font-black">{show.venue}</h2>
              <span className="rounded-full bg-lime-100 px-3 py-1 text-xs font-black text-lime-800">
                🎹 Markus dabei
              </span>
            </div>

            <p className="mt-1 text-sm font-bold text-zinc-500">
              {show.city} · {show.program}
            </p>

            {show.venue_address && (
              <p className="mt-2 text-sm text-zinc-500">
                {show.venue_address}
              </p>
            )}
          </div>

          <div className="rounded-3xl bg-white p-4 shadow-sm ring-1 ring-black/5">
            <Time label="Einlass" value={show.entry_time} />
            <Time label="Beginn" value={show.start_time} />
            <Time label="Soundcheck" value={portalValue(show, "soundcheck_time")} />
          </div>
        </div>

        <div className="mt-5 grid gap-3 md:grid-cols-2">
          <Info title="Piano / Technik" value={show.technik} highlight />
          <Info title="Ablauf" value={show.schedule} />
          <Info title="Kontakt" value={contactText(show)} />
          <Info title="Anreise" value={show.anreise || show.travel_details} />
          <Info title="Unterkunft" value={show.unterkunft || accommodationText(show)} />
          <Info title="Catering / Backstage" value={cateringText(show)} />
        </div>
      </div>
    </article>
  );
}

function Time({ label, value }: { label: string; value?: string | null }) {
  return (
    <div className="flex justify-between gap-4 border-b border-zinc-100 py-2 last:border-0">
      <span className="text-sm text-zinc-500">{label}</span>
      <span className="text-sm font-black">{value || "—"}</span>
    </div>
  );
}

function Info({
  title,
  value,
  highlight = false,
}: {
  title: string;
  value?: string | null;
  highlight?: boolean;
}) {
  return (
    <div
      className={[
        "rounded-3xl p-4 ring-1 ring-black/5",
        highlight ? "bg-lime-50" : "bg-white",
      ].join(" ")}
    >
      <p className="text-xs font-black uppercase tracking-wide text-zinc-400">
        {title}
      </p>
      <p className="mt-2 whitespace-pre-wrap text-sm leading-relaxed text-zinc-700">
        {value || "—"}
      </p>
    </div>
  );
}

function contactText(show: any) {
  return (
    [show.contact_name, show.contact_phone, show.contact_email]
      .filter(Boolean)
      .join("\n") || null
  );
}

function cateringText(show: any) {
  return (
    [show.catering_status, show.catering_details, show.backstage_equipment]
      .filter(Boolean)
      .join("\n") || null
  );
}

function accommodationText(show: any) {
  return (
    [show.accommodation_type, show.accommodation_notes]
      .filter(Boolean)
      .join("\n") || null
  );
}

function portalValue(show: any, key: string) {
  const data = show.portal_data;

  if (!data || typeof data !== "object") return null;

  const value = data[key];

  return typeof value === "string" ? value : null;
}